    /// <inheritdoc />
    public void Copy(CopyRequest request)
    {
        var source = SafeResolve(request.SourcePath);
        var destination = SafeResolve(request.DestinationPath);

        if (Directory.Exists(source))
        {
            CopyDirectory(source, destination, depth: 0);
