// ---------------------------------------------------------------------
// UploadAsync — uploaded file name sanitization (path-traversal /
// arbitrary file-write hardening).
//
// IFormFile.FileName is entirely client-controlled, so it must be treated
// as untrusted. The vulnerable implementation combined it verbatim with
// the resolved directory and wrote wherever the resulting path resolved,
// letting a name like "../escape.txt" or an absolute path place a file
// outside the home sandbox. The hardened implementation must either reject
// such names with ArgumentException or strip them to a safe leaf and write
// strictly inside the root — but in NO case may a file appear outside it.
// These tests pin that contract and fail against the vulnerable code.
// ---------------------------------------------------------------------

/// <summary>
/// The headline regression: a parent-traversal sequence in the uploaded
/// file name must never write outside the home root. The vulnerable
/// <c>Path.Combine(root, "../escape.txt")</c> resolves one level above
/// <c>Home</c> (into the content root) and creates a file there.
/// </summary>
[Fact]
public async Task UploadAsync_FileNameWithParentTraversal_DoesNotWriteOutsideRoot()
{
    var (service, root) = CreateService();
    // The OS-resolved location the vulnerable code would write to.
    var escapeTarget = Path.GetFullPath(Path.Combine(root, "..", "escape.txt"));
    Assert.False(File.Exists(escapeTarget));

    var file = FormFileFactory.CreateFormFile("../escape.txt", "x");
    try
    {
        await service.UploadAsync("", file);
    }
    catch (ArgumentException)
    {
        // A rejecting implementation also satisfies the contract; the
        // assertion below is the real guarantee.
    }

    Assert.False(File.Exists(escapeTarget),
        $"uploaded file escaped the home root to {escapeTarget}");
}

/// <summary>
/// Same property for a deeper traversal (the example from the security
/// finding). The escape target lands outside the per-test content root, so
/// it is cleaned up explicitly to avoid polluting the repo between runs.
/// </summary>
[Fact]
public async Task UploadAsync_FileNameWithMultipleParentTraversal_DoesNotWriteOutsideRoot()
{
    var (service, root) = CreateService();
    var escapeTarget = Path.GetFullPath(Path.Combine(root, "..", "..", "escape.txt"));
    Assert.False(File.Exists(escapeTarget));

    var file = FormFileFactory.CreateFormFile("../../escape.txt", "x");
    try
    {
        try
        {
            await service.UploadAsync("", file);
        }
        catch (ArgumentException)
        {
            // rejection is acceptable
        }

        Assert.False(File.Exists(escapeTarget),
            $"uploaded file escaped the home root to {escapeTarget}");
    }
    finally
    {
        // The escape target is outside the per-test content root and would
        // not be removed by Dispose, so clean it up to avoid polluting the
        // repository between runs (in case a regression ever writes here).
        if (File.Exists(escapeTarget))
        {
            File.Delete(escapeTarget);
        }
    }
}

/// <summary>
/// An absolute (rooted) file name must not be honored as an absolute
/// target. <c>Path.Combine(root, absolutePath)</c> returns the absolute
/// path verbatim, so the vulnerable code writes wherever the client
/// points. The target here is placed inside the content root (so Dispose
/// cleans it) but outside the home sandbox.
/// </summary>
[Fact]
public async Task UploadAsync_AbsoluteFileName_DoesNotWriteOutsideRoot()
{
    var (service, _) = CreateService();
    var absTarget = Path.Combine(_contentRoot, "stolen.txt");
    Assert.False(File.Exists(absTarget));

    var file = FormFileFactory.CreateFormFile(absTarget, "x");
    try
    {
        await service.UploadAsync("", file);
    }
    catch (ArgumentException)
    {
        // rejection is acceptable
    }

    Assert.False(File.Exists(absTarget),
        $"uploaded file was written to the absolute target {absTarget}");
}

/// <summary>
/// Empty or whitespace-only file names carry no usable leaf and must be
/// rejected with <see cref="ArgumentException"/> before any file is
/// created. (The vulnerable code either throws an unrelated exception for
/// an empty name or creates a whitespace-named file inside the root.)
/// </summary>
[Theory]
[InlineData("")]
[InlineData("   ")]
public async Task UploadAsync_EmptyOrWhitespaceFileName_ThrowsArgumentException(string fileName)
{
    var (service, root) = CreateService();
    var file = FormFileFactory.CreateFormFile(fileName, "x");

    await Assert.ThrowsAsync<ArgumentException>(() => service.UploadAsync("", file));

    // Nothing should have been written into the sandbox either.
    Assert.True(!Directory.Exists(root) || Directory.GetFiles(root).Length == 0);
}

/// <summary>
/// A file name containing characters invalid in file names (here the NUL
/// byte, which is in <see cref="Path.GetInvalidFileNameChars"/> on every
/// platform and is not a path separator, so it survives
/// <see cref="Path.GetFileName(string)"/>) must be rejected with
/// <see cref="ArgumentException"/>.
/// </summary>
[Fact]
public async Task UploadAsync_FileNameWithInvalidCharacters_ThrowsArgumentException()
{
    var (service, _) = CreateService();
    var file = FormFileFactory.CreateFormFile("bad\0name.txt", "x");

    await Assert.ThrowsAsync<ArgumentException>(() => service.UploadAsync("", file));
}

/// <summary>
/// A bare parent-reference name resolves to the parent of the sandbox
/// after the leaf is taken (<c>Path.GetFileName("..") == ".."</c>), so the
/// containment re-check must reject it with <see cref="ArgumentException"/>.
/// </summary>
[Fact]
public async Task UploadAsync_ParentReferenceFileName_ThrowsArgumentException()
{
    var (service, _) = CreateService();
    var file = FormFileFactory.CreateFormFile("..", "x");

    await Assert.ThrowsAsync<ArgumentException>(() => service.UploadAsync("", file));
}

/// <summary>
/// A file name that includes a directory component is sanitized down to
/// its leaf: the upload lands at the leaf name directly under the
/// resolved directory, never inside a subfolder implied by the
/// (untrusted) file name. This pins the documented "strips any leading
/// directories" behavior of <see cref="Path.GetFileName(string)"/>.
/// </summary>
[Fact]
public async Task UploadAsync_FileNameWithDirectoryComponent_StripsToLeafAndWritesUnderRoot()
{
    var (service, root) = CreateService();
    var file = FormFileFactory.CreateFormFile("subdir/report.txt", "payload");

    await service.UploadAsync("", file);

    Assert.True(File.Exists(Path.Combine(root, "report.txt")));
    Assert.False(File.Exists(Path.Combine(root, "subdir", "report.txt")));
    Assert.Equal("payload", await File.ReadAllTextAsync(Path.Combine(root, "report.txt")));
}

