// ---------------------------------------------------------------------
// Upload response path — uploaded file name sanitization.
//
// The response joins the directory query parameter with the uploaded file
// name. Because IFormFile.FileName is client-controlled, the response (and
// any downstream consumer of it) must use only the sanitized leaf, never
// the raw name — otherwise a traversal or absolute name leaks straight
// into the API response. These pin the post-fix contract that the leaf is
// extracted via Path.GetFileName. They fail against the vulnerable
// controller, which interpolates file.FileName verbatim.
// ---------------------------------------------------------------------

[Fact]
public async Task Upload_ResponsePath_UsesSanitizedLeaf_WhenFileNameContainsParentTraversal()
{
    var fake = new FakeFileService();
    var controller = CreateController(fake);
    var file = FormFileFactory.CreateFormFile("../escape.txt", "payload");

    var result = await controller.Upload(string.Empty, file);

    var ok = Assert.IsType<OkObjectResult>(result);
    Assert.Equal("escape.txt", GetProperty(ok.Value!, "path"));
}

[Fact]
public async Task Upload_ResponsePath_UsesSanitizedLeaf_WhenFileNameContainsDeepTraversal()
{
    var fake = new FakeFileService();
    var controller = CreateController(fake);
    var file = FormFileFactory.CreateFormFile("../../etc/escape.txt", "payload");

    var result = await controller.Upload(string.Empty, file);

    var ok = Assert.IsType<OkObjectResult>(result);
    Assert.Equal("escape.txt", GetProperty(ok.Value!, "path"));
}

[Fact]
public async Task Upload_ResponsePath_UsesSanitizedLeaf_WhenFileNameIsAbsolute()
{
    var fake = new FakeFileService();
    var controller = CreateController(fake);
    // A rooted name; on both Windows and Linux GetFileName returns the
    // final segment, so the absolute path never reaches the response.
    var file = FormFileFactory.CreateFormFile("/etc/passwd/secret.txt", "payload");

    var result = await controller.Upload(string.Empty, file);

    var ok = Assert.IsType<OkObjectResult>(result);
    Assert.Equal("secret.txt", GetProperty(ok.Value!, "path"));
}

[Fact]
public async Task Upload_ResponsePath_UsesSanitizedLeaf_WhenFileNameHasSubdirectory_AndPathProvided()
{
    var fake = new FakeFileService();
    var controller = CreateController(fake);
    var file = FormFileFactory.CreateFormFile("subdir/report.txt", "payload");

    var result = await controller.Upload("docs", file);

    var ok = Assert.IsType<OkObjectResult>(result);
    // The directory component of the file name is stripped; only the
    // query-parameter directory is prepended.
    Assert.Equal("docs/report.txt", GetProperty(ok.Value!, "path"));
}

[Fact]
public async Task Upload_ResponsePath_UsesSanitizedLeaf_WhenFileNameHasTraversal_AndPathProvided()
{
    var fake = new FakeFileService();
    var controller = CreateController(fake);
    var file = FormFileFactory.CreateFormFile("../escape.txt", "payload");

    var result = await controller.Upload("docs", file);

    var ok = Assert.IsType<OkObjectResult>(result);
    Assert.Equal("docs/escape.txt", GetProperty(ok.Value!, "path"));
}

/// <summary>
/// A null FileName must be tolerated (the fix coerces it to empty) and
/// must not surface the raw null in the response. Uses a dedicated double
/// so the null value is exact rather than dependent on FormFile's own
/// null handling.
/// </summary>
[Fact]
public async Task Upload_ResponsePath_NullFileName_DoesNotThrow_AndYieldsEmptyLeaf()
{
    var fake = new FakeFileService();
    var controller = CreateController(fake);
    var file = new NullFileNameFormFile();

    var result = await controller.Upload(string.Empty, file);

    var ok = Assert.IsType<OkObjectResult>(result);
    Assert.Equal(string.Empty, GetProperty(ok.Value!, "path"));
}

